/**
 * Verse timestamp service — provides exact verse start times for audio follow-along.
 *
 * Timestamps are in SECONDS (float).
 * expo-av's currentPosition is in MILLISECONDS — divide by 1000 before comparing.
 *
 * Example:
 *   const timestamps = await getChapterTimestamps('web', 'GEN', 1);
 *   // timestamps[1] = 0.0, timestamps[2] = 4.2, ...
 *   // In bibleReaderModel getEstimatedFollowAlongVerse:
 *   //   timestamps[vn] <= currentPosition / 1000
 *
 * Files are bundled at: assets/timestamps/<TRANSLATION_UPPER>/<BOOK>_<CHAPTER_PADDED>.json
 * Generated by: npm run generate-timestamps -- --translation web
 *
 * Phase 14 note: this interface is stable for future remote URL loading.
 * When backend-driven timestamps are available, replace the require() path
 * with a fetch call without changing the return type or callers.
 */

export type VerseTimestamps = Record<number, number>;

// Static require map for Metro bundler — Metro needs static string paths.
// We build this map at module load time. Unknown chapters return null.
// Keys: "<TRANSLATION_UPPER>/<BOOK>_<CHAPTER_PADDED>"
type TimestampRequireFn = () => Record<string, number>;

