/**
 * Returns verse timestamps for a given chapter, or null if not available.
 *
 * translationId: 'web' | 'bsb' (lowercase, matches translation IDs in the app)
 * bookId: 3-letter book ID e.g. 'GEN', 'MAT', '1CO' (matches src/constants/books.ts)
 * chapter: 1-indexed chapter number
 *
 * Falls back to word-weight estimation in bibleReaderModel when null is returned.
 */
export async function getChapterTimestamps(
  translationId: string,
  bookId: string,
  chapter: number
): Promise<VerseTimestamps | null> {
  try {
    const chapterPadded = String(chapter).padStart(3, '0');
    const key = `${translationId.toUpperCase()}/${bookId}_${chapterPadded}`;
    const requireFn = TIMESTAMP_REQUIRES[key];

    if (!requireFn) {
      return null;
    }

    const raw = requireFn() as Record<string, number>;

    // Convert string keys to number keys (JSON keys are always strings)
    const result: VerseTimestamps = {};
    for (const [k, v] of Object.entries(raw)) {
      const verseNum = Number(k);
      if (!Number.isNaN(verseNum) && typeof v === 'number') {
        result[verseNum] = v;
      }
    }

    return Object.keys(result).length > 0 ? result : null;
  } catch {
    // Gracefully return null if asset is missing or malformed
    return null;
  }
}

/**
 * Returns true if timestamps are available for a translation.
 * Use to conditionally show follow-along UI affordances.
 */
export function hasTimestampsForTranslation(translationId: string): boolean {
  const prefix = `${translationId.toUpperCase()}/`;
  return Object.keys(TIMESTAMP_REQUIRES).some((key) => key.startsWith(prefix));
}
